qnTypes = [...new Set(detail.map(d =&gt; d.qn))].sort()
languages = [...new Set(detail.map(d =&gt; d.language))].sort()























viewof selectedCountry = Inputs.select(["All", ...countries], {label: "Country", value: "CN"})
